try {
  const incoming = $input.first()?.json || {};
  const body = incoming.body || incoming || {};

  const rawOriginalInput =
    body.originalInput ||
    body.chatInput ||
    body.message ||
    body.input ||
    body.text ||
    "";

  const originalInput = String(rawOriginalInput || "")
    .replace(/\s+\d{1,2}:\d{2}\s*$/g, "")
    .replace(/\s+/g, " ")
    .trim();

  if (!originalInput) {
    throw new Error("Nenhuma mensagem textual recebida.");
  }

  return [{
    json: {
      originalInput,
      chatInput: originalInput,
      userQuestion: originalInput,

      hoje: new Date().toISOString().split("T")[0],

      job_id: body.job_id || null,
      sessionId: body.sessionId || body.conversationId || null,
      conversationId: body.conversationId || body.sessionId || null,

      callback_url: body.callback_url || null,
      callback_token: body.callback_token || null,

      error: false
    }
  }];
} catch (error) {
  const incoming = $input.first()?.json || {};
  const body = incoming.body || incoming || {};

  return [{
    json: {
      originalInput: "",
      chatInput: "",
      userQuestion: "",

      hoje: new Date().toISOString().split("T")[0],

      job_id: body.job_id || null,
      sessionId: body.sessionId || body.conversationId || null,
      conversationId: body.conversationId || body.sessionId || null,

      callback_url: body.callback_url || null,
      callback_token: body.callback_token || null,

      error: true,
      errorType: "input_error",
      errorMessage: error.message
    }
  }];
}

try {
  const s = $('Extrair pergunta').first().json || {};

  const originalInput = String(s.originalInput || "")
    .replace(/\s+\d{1,2}:\d{2}\s*$/g, "")
    .replace(/\s+/g, " ")
    .trim();

  const n = originalInput
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim();

  const simpleInputs = new Set([
    "ola",
    "oi",
    "bom dia",
    "boa tarde",
    "boa noite",
    "e ai",
    "eai",
    "hello",
    "hi",
    "ping",
    "ajuda",
    "help",
    "comandos",
    "como funciona",
    "o que voce faz"
  ]);

  const sampleTerms = [
    "amostra",
    "amostras",
    "exemplo",
    "exemplos",
    "caso exemplo",
    "casos exemplo",
    "alguns casos",
    "algumas linhas",
    "linhas de exemplo",
    "registros de exemplo",
    "me mostre casos",
    "me mostre exemplos",
    "traga exemplos",
    "traga amostras"
  ];

  const detailTerms = [
    "liste",
    "listar",
    "listagem",
    "trecho",
    "trechos",
    "evidencia",
    "evidencias",
    "detalhe",
    "detalhes",
    "detalhado",
    "detalhada",
    "caso",
    "casos",
    "score",
    "estratificacao",
    "informacoes",
    "motivo",
    "motivos",
    "justificativa",
    "justificativas",
    "levaram",
    "levou",
    "influenciaram"
  ];

  const aggregationTerms = [
    "quantos",
    "quantas",
    "quantidade",
    "contagem",
    "total",
    "soma",
    "media",
    "percentual",
    "porcentagem",
    "distribuicao",
    "agregado",
    "consolidado",
    "relatorio"
  ];

  function extractSampleSize(text) {
    const patterns = [
      /\b(\d{1,2})\s+(amostras|exemplos|casos|linhas|registros)\b/i,
      /\b(amostras|exemplos|casos|linhas|registros)\s+(de\s+)?(\d{1,2})\b/i,
      /\b(top|primeiros|primeiras)\s+(\d{1,2})\b/i
    ];

    for (const pattern of patterns) {
      const match = text.match(pattern);

      if (!match) {
        continue;
      }

      const value = Number(match[1] || match[3] || match[2]);

      if (Number.isFinite(value) && value > 0) {
        return Math.min(value, 20);
      }
    }

    return 5;
  }

  const isSimple = simpleInputs.has(n);

  const sampleMode =
    !isSimple &&
    sampleTerms.some(term => n.includes(term));

  const sampleSize = sampleMode
    ? extractSampleSize(n)
    : null;

  const wantsRows =
    !isSimple &&
    (
      sampleMode ||
      detailTerms.some(term => n.includes(term))
    );

  const hasAggregationIntent =
    !isSimple &&
    !sampleMode &&
    aggregationTerms.some(term => n.includes(term));

  const outputMode = sampleMode
    ? "sample"
    : (wantsRows ? "rows" : "summary");

  return [{
    json: {
      originalInput,
      chatInput: originalInput,
      userQuestion: originalInput,

      hoje: s.hoje,
      sessionId: s.sessionId,
      conversationId: s.conversationId,
      job_id: s.job_id,
      callback_url: s.callback_url,
      callback_token: s.callback_token,

      is_simple: isSimple,

      output_mode: outputMode,
      wants_rows: wantsRows,

      sample_mode: sampleMode,
      sample_size: sampleSize,

      has_aggregation_intent: hasAggregationIntent,
      has_detail_intent: wantsRows,
      wants_aggregations: hasAggregationIntent,

      error: false
    }
  }];
} catch (error) {
  const s = $('Extrair pergunta').first().json || {};

  return [{
    json: {
      ...s,
      is_simple: false,
      output_mode: "summary",
      wants_rows: false,
      sample_mode: false,
      sample_size: null,
      wants_aggregations: false,
      error: true,
      errorType: "router_error",
      errorMessage: error.message
    }
  }];
}

