const current = $json || {};
const raw = current.output ?? current.text ?? "";

function getNodeJson(nodeName) {
  try {
    return $(nodeName).first().json || {};
  } catch {
    return {};
  }
}

const baseEntrada = getNodeJson("Preparar Entrada Orquestrador");
const memoryEntrada = getNodeJson("Normalizar Aprendizado");
const retryEntrada = getNodeJson("Preparar Retry");

const src = {
  ...baseEntrada,
  ...memoryEntrada,
  ...retryEntrada,
  ...current
};

const steps = current.intermediateSteps || [];

function strip(value) {
  return String(value || "")
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();
}

function parse(value) {
  if (!value) return null;
  if (typeof value === "object") return value;

  try {
    return JSON.parse(strip(value));
  } catch {
    return null;
  }
}

function parseNested(value) {
  const parsed = parse(value);

  if (!parsed || typeof parsed !== "object") {
    return null;
  }

  for (const key of [
    "output",
    "result",
    "response",
    "toolResult",
    "final_output",
    "finalOutput"
  ]) {
    if (typeof parsed[key] === "string") {
      const nested = parse(parsed[key]);

      if (nested && typeof nested === "object") {
        return nested;
      }
    }
  }

  return parsed;
}

function collectToolRuns(root) {
  const runs = [];
  const seen = new Set();

  function walk(value) {
    if (!value || typeof value !== "object" || seen.has(value)) {
      return;
    }

    seen.add(value);

    if (Array.isArray(value)) {
      value.forEach(walk);
      return;
    }

    const toolName =
      value.action?.tool ||
      value.action?.toolName ||
      value.tool ||
      value.toolName ||
      value.name ||
      value.nodeName ||
      "";

    const toolInput =
      value.action?.toolInput ??
      value.toolInput ??
      value.input ??
      value.args ??
      value.parameters ??
      null;

    const observation =
      value.observation ??
      value.output ??
      value.result ??
      value.response ??
      value.toolResult ??
      null;

    if (toolName && observation !== null && observation !== undefined) {
      runs.push({
        toolName: String(toolName),
        toolInput,
        observation
      });
    }

    Object.values(value).forEach(walk);
  }

  walk(root);
  return runs;
}

function lastRun(runs, regex) {
  const matches = runs.filter(run =>
    regex.test(String(run.toolName || "").toLowerCase())
  );

  return matches.length ? matches[matches.length - 1] : null;
}

function trimText(value, max = 700) {
  if (value === null || value === undefined) {
    return value;
  }

  const text = String(value);

  return text.length > max
    ? text.slice(0, max) + "..."
    : text;
}

function compactRows(rows) {
  if (!Array.isArray(rows)) {
    return [];
  }

  return rows.map(row => ({
    estrato: row.estrato ?? null,
    classificacao: row.classificacao ?? row.estrato ?? null,
    id_atendimento: row.id_atendimento ?? null,
    id_paciente: row.id_paciente ?? null,
    data_atendimento: row.data_atendimento ?? null,
    campo_origem: row.campo_origem ?? null,
    termo_detectado: row.termo_detectado ?? null,
    trecho_evidencia: trimText(row.trecho_evidencia ?? row.evidencia ?? null, 700),
    score: row.score ?? null,
    cid_codigo_txt: row.cid_codigo_txt ?? row.cid_codigo ?? null,
    flg_cirurgica: row.flg_cirurgica ?? null,
    nome_profissional: row.nome_profissional ?? null
  }));
}

function rowsFromSqlPayload(payload) {
  if (!payload || typeof payload !== "object") {
    return [];
  }

  const data = payload.data || payload;

  const rows =
    data.rows ||
    data.data?.rows ||
    payload.rows ||
    [];

  return Array.isArray(rows) ? rows : [];
}

function safeNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

const toolRuns = collectToolRuns(steps);

const ragRun = lastRun(
  toolRuns,
  /rag_blueprint|rag blueprint|ferramenta rag|rag/
);

const sqlRun = lastRun(
  toolRuns,
  /sql_executor|sql executor|ferramenta sql|sql/
);

const ragObs = ragRun ? parseNested(ragRun.observation) : null;
const sqlObs = sqlRun ? parseNested(sqlRun.observation) : null;
const out = parse(raw) || {};

const previousQueryResult = src.query_result || null;

const previousExecutorSummary =
  src.executor_summary ||
  previousQueryResult?.summary ||
  {};

const previousExecutorRowCount =
  src.executor_row_count ??
  previousQueryResult?.row_count ??
  previousQueryResult?.rows?.length ??
  0;

const previousHasData =
  src.has_data === true ||
  Boolean(previousQueryResult);

const ragUsed =
  out.rag_used === true ||
  src.rag_used === true ||
  Boolean(ragRun);

const sqlUsed =
  out.sql_used === true ||
  src.sql_used === true ||
  Boolean(sqlRun);

const specializedUsed = ragUsed || sqlUsed;

const ragContext = trimText(
  out.rag_context ||
  ragObs?.rag_context ||
  ragObs?.context ||
  ragObs?.rules ||
  ragObs?.output ||
  ragObs?.final_answer ||
  src.rag_context ||
  "",
  3000
);

let executor = null;

if (sqlObs && typeof sqlObs === "object") {
  const data = sqlObs.data || sqlObs;
  const rowsRaw = rowsFromSqlPayload(sqlObs);
  const summary = sqlObs.summary || data.summary || {};

  executor = {
    execution_status:
      sqlObs.execution_status ||
      sqlObs.status ||
      (sqlObs.error ? "error" : "success"),

    summary,

    rows: compactRows(rowsRaw),

    row_count:
      sqlObs.row_count ??
      summary.total_registros ??
      rowsRaw.length,

    truncated: sqlObs.truncated === true,

    sql: sqlObs.sql || null,

    error: sqlObs.error || null,

    limitations: Array.isArray(sqlObs.limitations)
      ? sqlObs.limitations
      : []
  };
}

const analysisType = String(
  out.analysis_type ||
  src.analysis_type ||
  ""
).toLowerCase();

const isSimple =
  src.is_simple === true ||
  (
    ["saudacao", "conceitual", "nao_aplicavel"].includes(analysisType) &&
    !specializedUsed
  );

const dataIntent =
  !isSimple &&
  (
    src.has_aggregation_intent === true ||
    src.has_detail_intent === true ||
    /catarata|cirurgia|prontuario|prontuário|relat[oó]rio|score|estratifica|evid[eê]ncia|trecho|abril|dados|registro|classifica/i.test(src.originalInput || "")
  );

let error = out.error === true || src.error === true;
let errorType = out.errorType || src.errorType || null;
let errorMessage = out.errorMessage || src.errorMessage || null;

let finalAnswer = String(
  out.final_answer ||
  out.output ||
  ""
).trim();

if (executor && executor.execution_status === "error") {
  error = true;
  errorType = "sql_executor_error";
  errorMessage = String(
    executor.error?.message ||
    executor.error ||
    "sql_executor_error"
  );

  finalAnswer = "Não foi possível concluir a análise porque houve erro ao consultar os dados.";
}

if (!finalAnswer && executor && executor.execution_status !== "error") {
  const summary = executor.summary || {};
  const total = summary.total_registros ?? executor.row_count ?? 0;

  if (total === 0) {
    finalAnswer = "Consulta executada, mas não foram encontrados registros para os critérios informados.";
  } else {
    const metrics = [];

    for (const [label, key] of [
      ["Positivos", "positivos"],
      ["Prováveis", "provaveis"],
      ["Negativos", "negativos"],
      ["Pós-operatórios/irrelevantes", "pos_operatorios"],
      ["Percentual de positivos", "percentual_positivos"],
      ["Percentual de prováveis", "percentual_provaveis"],
      ["Percentual de negativos", "percentual_negativos"]
    ]) {
      if (summary[key] !== undefined && summary[key] !== null) {
        metrics.push(
          `- ${label}: ${summary[key]}${key.startsWith("percentual") ? "%" : ""}`
        );
      }
    }

    finalAnswer = `Encontrei ${total} registros para a análise solicitada.`;

    if (metrics.length) {
      finalAnswer += `\n\nResumo:\n${metrics.join("\n")}`;
    }

    if (src.wants_rows && executor.rows.length) {
      const examples = executor.rows.map((row, index) =>
        `${index + 1}. ${row.id_atendimento ?? "não informado"} | ${row.classificacao ?? row.estrato ?? "sem classificação"} | Score: ${row.score ?? "não informado"} | ${trimText(row.trecho_evidencia, 220) || "sem trecho"}`
      );

      finalAnswer += `\n\nExemplos:\n${examples.join("\n")}`;
    }
  }
}

if (!finalAnswer && src.is_retry === true && src.final_answer) {
  finalAnswer = String(src.final_answer || "").trim();
}

if (!finalAnswer) {
  finalAnswer = isSimple
    ? "Olá! Posso ajudar a consultar, resumir ou classificar registros relacionados à cirurgia de catarata."
    : "Não consegui montar uma resposta confiável para essa solicitação.";
}

const queryResult =
  executor && executor.execution_status !== "error"
    ? {
        summary: executor.summary,
        row_count: executor.row_count,
        truncated: executor.truncated,
        rows: executor.rows,
        limitations: executor.limitations
      }
    : previousQueryResult;

const executorSummary =
  executor?.summary ||
  previousExecutorSummary ||
  {};

const executorRowCount =
  executor?.row_count ??
  previousExecutorRowCount ??
  0;

const hasData =
  Boolean(executor && executor.execution_status !== "error") ||
  previousHasData;

const userAskedForSql =
  out.user_asked_for_sql === true ||
  src.user_asked_for_sql === true;

const sqlValue =
  userAskedForSql
    ? (out.sql || executor?.sql || src.sql || null)
    : null;

const retryCount = safeNumber(src.retry_count, 0);
const isRetry = src.is_retry === true;
const retryApplied = isRetry === true;

const judgeRequired =
  specializedUsed &&
  !error;

return {
  json: {
    originalInput: src.originalInput,
    chatInput: src.chatInput,
    userQuestion: src.userQuestion,

    hoje: src.hoje,
    sessionId: src.sessionId,
    conversationId: src.conversationId,
    job_id: src.job_id,
    callback_url: src.callback_url,
    callback_token: src.callback_token,

    final_answer: finalAnswer,
    output: finalAnswer,

    analysis_type:
      out.analysis_type ||
      src.analysis_type ||
      (isSimple ? "saudacao" : (dataIntent ? "relatorio" : "nao_aplicavel")),

    periodo:
      out.periodo ||
      src.periodo ||
      { inicio: null, fim_exclusivo: null },

    unit_of_analysis:
      out.unit_of_analysis ||
      src.unit_of_analysis ||
      "nao_aplicavel",

    sql: sqlValue,
    user_asked_for_sql: userAskedForSql,

    error,
    errorType,
    errorMessage,
    validated: !error,

    rag_used: ragUsed,
    sql_used: sqlUsed,
    rag_context: ragContext,

    executor_summary: executorSummary,
    executor_row_count: executorRowCount,
    has_data: hasData,

    query_result: queryResult,

    retry_count: retryCount,
    is_retry: isRetry,
    retry_context: src.retry_context || null,
    retry_applied: retryApplied,

    memory_context: src.memory_context || null,
    memory_loaded: src.memory_loaded === true,
    memory_count: src.memory_count ?? null,

    orchestration: {
      ...(src.orchestration || {}),

      rag_used: ragUsed,
      sql_used: sqlUsed,

      judge_used: false,
      judge_required: judgeRequired,

      retry_used: retryApplied,

      agents_called: Array.from(new Set([
        ...(src.orchestration?.agents_called || []),
        "orchestrator",
        ...(ragUsed ? ["rag_blueprint"] : []),
        ...(sqlUsed ? ["sql_executor"] : []),
        ...(retryApplied ? ["orchestrator_retry"] : [])
      ]))
    },

    judge_output: isSimple
      ? {
          judge_passed: true,
          overall_score: 1,
          source: "light_judge"
        }
      : {
          judge_passed: null,
          overall_score: null,
          source: judgeRequired ? "pending_metric_judge" : "not_required"
        },

    judge_passed: isSimple ? true : null,
    judge_score: isSimple ? 1 : null,

    needs_judge_evaluation: judgeRequired,

    issues: error
      ? [
          {
            type: errorType || "error",
            message: errorMessage || "Erro não especificado."
          }
        ]
      : []
  }
};

return {
  json: {
    ...$json,
    needs_judge_evaluation: false,
    orchestration: {
      ...($json.orchestration || {}),
      judge_used: false,
      judge_required: false
    }
  }
};

const candidate = $("Normalizar Orquestrador").first().json || {};
const judge = $json || {};

const judgePassed =
  judge.judge_passed ??
  judge.passed ??
  judge.judgment?.judge_passed ??
  null;

const judgeScore =
  judge.overall_score ??
  judge.score_final ??
  judge.judgment?.overall_score ??
  judge.judgment?.score_final ??
  null;

return {
  json: {
    ...candidate,

    final_answer: candidate.final_answer,
    output: candidate.output || candidate.final_answer,

    error: candidate.error === true,
    errorType: candidate.errorType || null,
    errorMessage: candidate.errorMessage || null,

    validated: candidate.error !== true,

    judge_output: judge,
    judge_passed: judgePassed,
    judge_score: judgeScore,

    orchestration: {
      ...(candidate.orchestration || {}),
      judge_used: true,
      judge_required: true,
      agents_called: Array.from(new Set([
        ...(candidate.orchestration?.agents_called || []),
        "judge_qualidade"
      ]))
    },

    timestamp: new Date().toISOString()
  }
};

const data = $json || {};

function clip(value, max = 900) {
  const text = String(value || '').trim();
  return text.length > max ? text.slice(0, max) + '...' : text;
}

function asNumber(value, fallback = null) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function normalizeText(value) {
  return String(value || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function safeJson(value) {
  try {
    return JSON.stringify(value || {});
  } catch {
    return String(value || '');
  }
}

function hasAny(text, terms) {
  return terms.some(term => text.includes(term));
}

function pushLesson(lessons, item) {
  if (!item || !item.lesson) return;

  const key = `${item.category || ''}::${item.lesson || ''}`;

  if (lessons.some(existing => `${existing.category || ''}::${existing.lesson || ''}` === key)) {
    return;
  }

  lessons.push({
    category: item.category || 'geral',
    lesson: item.lesson,
    reason: clip(item.reason || '', 900),
    confidence: Number(item.confidence || 0.75)
  });
}

function extractJudgeInfo(d) {
  const judge = d.judge_output || {};

  const judgePassed =
    d.judge_passed ??
    judge.judge_passed ??
    judge.passed ??
    judge.judgment?.judge_passed ??
    null;

  const judgeScore =
    asNumber(d.judge_score, null) ??
    asNumber(judge.overall_score, null) ??
    asNumber(judge.score_final, null) ??
    asNumber(judge.judgment?.overall_score, null) ??
    asNumber(judge.judgment?.score_final, null);

  const issues = [
    ...(Array.isArray(d.issues) ? d.issues : []),
    ...(Array.isArray(judge.issues) ? judge.issues : []),
    ...(Array.isArray(judge.problems) ? judge.problems : []),
    ...(Array.isArray(judge.judgment?.issues) ? judge.judgment.issues : []),
    ...(Array.isArray(judge.findings) ? judge.findings : [])
  ];

  const judgeText = normalizeText([
    safeJson(judge),
    safeJson(issues),
    d.errorType || '',
    d.errorMessage || '',
    d.analysis_type || '',
    d.originalInput || '',
    d.final_answer || ''
  ].join(' '));

  return {
    judge,
    judgePassed,
    judgeScore,
    issues,
    judgeText
  };
}

function lessonFromExecution(d) {
  const lessons = [];

  const originalInput = String(d.originalInput || d.userQuestion || d.chatInput || '');
  const inputText = normalizeText(originalInput);
  const analysisType = normalizeText(d.analysis_type || '');
  const finalAnswerText = normalizeText(d.final_answer || '');

  const {
    judgePassed,
    judgeScore,
    judgeText
  } = extractJudgeInfo(d);

  const lowJudgeScore =
    judgeScore !== null &&
    judgeScore !== undefined &&
    Number(judgeScore) < 0.75;

  const judgeFailed =
    judgePassed === false ||
    lowJudgeScore;

  const isSampleIntent =
    hasAny(inputText, [
      'amostra',
      'amostras',
      'exemplo',
      'exemplos',
      'casos exemplo',
      'algumas linhas',
      'linhas de exemplo',
      'registros de exemplo'
    ]) ||
    analysisType.includes('amostra');

  const isEvidenceIntent =
    hasAny(inputText, [
      'evidencia',
      'evidencias',
      'evidência',
      'evidências',
      'trecho',
      'trechos',
      'justificativa',
      'justificativas',
      'motivo',
      'motivos',
      'termo detectado',
      'campo de origem'
    ]);

  const isAggregationIntent =
    hasAny(inputText, [
      'quantos',
      'quantas',
      'quantidade',
      'contagem',
      'total',
      'percentual',
      'porcentagem',
      'distribuicao',
      'distribuição',
      'media',
      'média',
      'resumo',
      'relatorio',
      'relatório'
    ]);

  if (d.error === true && d.errorType) {
    pushLesson(lessons, {
      category: 'erro_recorrente',
      lesson: `Quando ocorrer ${d.errorType}, tratar o erro antes de responder ao usuário.`,
      reason: d.errorMessage || d.errorType,
      confidence: 0.75
    });
  }

  if (d.errorType === 'sql_executor_error') {
    pushLesson(lessons, {
      category: 'sql',
      lesson: 'Validar SQL de forma determinística antes de executar, respeitando sintaxe Athena/Presto e tipos compatíveis.',
      reason: 'Execução SQL falhou ou foi rejeitada pelo executor.',
      confidence: 0.9
    });
  }

  if (d.errorType === 'missing_rag_context') {
    pushLesson(lessons, {
      category: 'rag_sql_handoff',
      lesson: 'Nunca chamar SQL sem rag_context clínico real retornado pelo RAG.',
      reason: 'O contexto RAG estava ausente, genérico ou inválido.',
      confidence: 0.95
    });
  }

  if (judgeFailed) {
    pushLesson(lessons, {
      category: 'qualidade',
      lesson: 'Quando o Judge pontuar baixo ou reprovar, revisar aderência aos dados, completude, ausência de invenção e formato final.',
      reason: `judge_passed=${judgePassed}; judge_score=${judgeScore}`,
      confidence: 0.8
    });
  }

  if (judgeFailed && isSampleIntent) {
    pushLesson(lessons, {
      category: 'amostra',
      lesson: 'Quando o usuário pedir amostra, retornar poucas linhas individuais completas, sem agregações, percentuais ou resumo consolidado.',
      reason: `Pedido de amostra teve baixa avaliação do Judge. judge_score=${judgeScore}`,
      confidence: 0.95
    });
  }

  if (
    judgeFailed &&
    isSampleIntent &&
    (
      hasAny(finalAnswerText, ['percentual', 'porcentagem', 'total', 'resumo', 'distribuicao', 'distribuição']) ||
      hasAny(judgeText, ['agregacao indevida', 'agregação indevida', 'agregado', 'consolidado'])
    )
  ) {
    pushLesson(lessons, {
      category: 'amostra_sem_agregacao',
      lesson: 'Em modo amostra, não consolidar resultados; mostrar registros reais com id_atendimento, id_paciente, data, classificação, score e evidência.',
      reason: 'O Judge indicou ou o texto final sugere uso de agregações em uma solicitação de amostra.',
      confidence: 0.97
    });
  }

  if (judgeFailed && isEvidenceIntent) {
    pushLesson(lessons, {
      category: 'evidencias',
      lesson: 'Quando o usuário pedir evidências, incluir campo de origem, termo detectado e trecho textual sempre que disponíveis.',
      reason: `Pedido de evidências teve baixa avaliação do Judge. judge_score=${judgeScore}`,
      confidence: 0.9
    });
  }

  if (
    judgeFailed &&
    hasAny(judgeText, [
      'inventou',
      'invenção',
      'invencao',
      'alucinacao',
      'alucinação',
      'sem base',
      'nao sustentado',
      'não sustentado',
      'dados nao encontrados',
      'dados não encontrados'
    ])
  ) {
    pushLesson(lessons, {
      category: 'anti_alucinacao',
      lesson: 'Nunca inventar totais, percentuais, pacientes, atendimentos, scores, classificações ou evidências ausentes no resultado SQL.',
      reason: 'O Judge indicou possível resposta sem sustentação nos dados.',
      confidence: 0.98
    });
  }

  if (
    judgeFailed &&
    hasAny(judgeText, [
      'rag',
      'contexto clinico',
      'contexto clínico',
      'regua',
      'régua',
      'classificacao',
      'classificação'
    ])
  ) {
    pushLesson(lessons, {
      category: 'rag_clinico',
      lesson: 'Para perguntas substantivas, usar o RAG como régua clínica antes do SQL e não substituir a régua por memória ou exemplos anteriores.',
      reason: 'O Judge indicou problema relacionado ao uso do RAG ou da classificação clínica.',
      confidence: 0.92
    });
  }

  if (
    judgeFailed &&
    isAggregationIntent &&
    hasAny(judgeText, [
      'incompleto',
      'faltou metrica',
      'faltou métrica',
      'sem percentual',
      'sem total',
      'sem estratificacao',
      'sem estratificação'
    ])
  ) {
    pushLesson(lessons, {
      category: 'relatorio_metricas',
      lesson: 'Em pedidos de relatório, contagem ou distribuição, incluir total, estratificação, percentuais quando disponíveis e interpretação objetiva.',
      reason: 'O Judge indicou incompletude em resposta agregada ou relatório.',
      confidence: 0.9
    });
  }

  if (
    judgeFailed &&
    hasAny(judgeText, [
      'json invalido',
      'json inválido',
      'formato invalido',
      'formato inválido',
      'nao retornou json',
      'não retornou json'
    ])
  ) {
    pushLesson(lessons, {
      category: 'formato_saida',
      lesson: 'O orquestrador deve retornar somente JSON válido no formato contratado, sem markdown, comentários ou texto fora do objeto.',
      reason: 'O Judge indicou problema de formato na saída.',
      confidence: 0.95
    });
  }

  if (
    d.rag_used === true &&
    d.sql_used === true &&
    d.error !== true &&
    judgeScore !== null &&
    Number(judgeScore) >= 0.85
  ) {
    pushLesson(lessons, {
      category: 'bom_padrao',
      lesson: 'Para perguntas substantivas, o padrão RAG antes de SQL produz resposta mais confiável.',
      reason: 'Execução com RAG, SQL e boa avaliação do Judge.',
      confidence: 0.85
    });
  }

  if (
    d.rag_used === true &&
    d.sql_used === true &&
    d.error !== true &&
    isSampleIntent &&
    judgeScore !== null &&
    Number(judgeScore) >= 0.85
  ) {
    pushLesson(lessons, {
      category: 'bom_padrao_amostra',
      lesson: 'Em pedidos de amostra, o melhor padrão é retornar poucos registros individuais com evidência textual, sem resumo agregado.',
      reason: 'Execução de amostra aprovada pelo Judge.',
      confidence: 0.88
    });
  }

  return lessons;
}

const lessons = lessonFromExecution(data);

return lessons.map(item => ({
  json: {
    memory_key: 'iris_cirurgias',
    category: item.category,
    lesson: item.lesson,
    reason: item.reason,
    confidence: item.confidence,
    source_job_id: data.job_id || null,
    source_session_id: data.sessionId || null,
    source_analysis_type: data.analysis_type || null,
    source_error_type: data.errorType || null
  }
}));

const entrada = $('Preparar Entrada Orquestrador').first().json || {};
const first = $input.first()?.json || {};

function parseMaybeJson(value, fallback = []) {
  if (value === null || value === undefined || value === '') {
    return fallback;
  }

  if (Array.isArray(value)) {
    return value;
  }

  if (typeof value === 'object') {
    return value;
  }

  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
}

function compactText(value, max = 2200) {
  const text = typeof value === 'string'
    ? value
    : JSON.stringify(value || {}, null, 2);

  return text.length > max
    ? text.slice(0, max) + '...'
    : text;
}

function cleanText(value, max = 500) {
  const text = String(value || '')
    .replace(/\s+/g, ' ')
    .trim();

  return text.length > max
    ? text.slice(0, max) + '...'
    : text;
}

const rawAprendizados = parseMaybeJson(first.aprendizados, []);

const aprendizados = Array.isArray(rawAprendizados)
  ? rawAprendizados.map(row => ({
      categoria: cleanText(row.category || '', 80),
      regra: cleanText(row.lesson || '', 500),
      motivo: cleanText(row.reason || '', 500),
      confianca: Number(row.confidence || 0),
      usos: Number(row.usage_count || 0)
    }))
  : [];

const regrasPrioritarias = aprendizados
  .filter(item => item.confianca >= 0.85)
  .map(item => `${item.categoria}: ${item.regra}`)
  .slice(0, 10);

return {
  json: {
    ...entrada,

    memory_context: compactText({
      tipo: 'aprendizados_curados_do_projeto',
      uso: [
        'Use como checklist operacional preventivo.',
        'Não copie respostas antigas.',
        'Não substitui RAG.',
        'Não substitui SQL.',
        'Não invente dados ausentes.',
        'Em conflito entre memória e dados/RAG, dados e RAG vencem.'
      ],
      regras_prioritarias: regrasPrioritarias,
      aprendizados
    }, 2200),

    memory_loaded: true,
    memory_count: aprendizados.length
  }
};

const d = $json || {};
const judge = d.judge_output || {};

function clip(value, max = 2500) {
  const text = typeof value === 'string'
    ? value
    : JSON.stringify(value || {}, null, 2);

  return text.length > max
    ? text.slice(0, max) + '...'
    : text;
}

const judgeCritique = {
  judge_passed: d.judge_passed ?? judge.judge_passed ?? null,
  judge_score: d.judge_score ?? judge.overall_score ?? judge.score_final ?? null,
  issues:
    judge.issues ||
    judge.problems ||
    judge.judgment?.issues ||
    d.issues ||
    [],
  feedback:
    judge.feedback ||
    judge.reason ||
    judge.recommendation ||
    judge.correction_hint ||
    null
};

return {
  json: {
    ...d,

    retry_count: Number(d.retry_count || 0) + 1,
    is_retry: true,

    retry_context: clip({
      tipo: 'retry_pos_judge',
      instrucao: 'Corrija a resposta anterior com base na crítica do Judge. Não invente dados. Use somente RAG, SQL e resultados já disponíveis.',
      critica_do_judge: judgeCritique,
      resposta_anterior: d.final_answer || '',
      query_result: d.query_result || null,
      executor_summary: d.executor_summary || {},
      rag_context: d.rag_context || ''
    }, 2500),

    memory_context:
      d.memory_context ||
      $('Normalizar Aprendizado').first().json.memory_context ||
      '{}'
  }
};
